from haystack import component

@component
class JailbreakDetector:
    def __init__(self):
        self.jailbreak_patterns = [
            r'dan.*jailbreak',
            r'ignore.*previous.*instructions',
            r'you are.*gpt-4',
            r'roleplay.*as.*hacker',
            r'base64.*decode',
            r'exec\(',
            r'system\(',
            r'rm\s+-rf',
        ]

    @component.output_types(has_jailbreak=bool, risk_score=float)
    def run(self, query: str):
        import re
        score = 0
        for pattern in self.jailbreak_patterns:
            if re.search(pattern, query.lower(), re.IGNORECASE):
                score += 1
        return {'has_jailbreak': score > 0, 'risk_score': score / len(self.jailbreak_patterns)}

from haystack import Pipeline

safety_pipeline = Pipeline()
safety_pipeline.add_component("response_validator", JailbreakDetector())

@component
class ResponseValidator:
    @component.output_types(is_safe=bool)
    def run(self, response: str):
        unsafe_indicators = [
            'here is your flag',
            'api_key',
            'password',
            'executed successfully',
            'root access granted'
        ]
        is_unsafe = any(indicator in response.lower() for indicator in unsafe_indicators)
        return {'is_safe': not is_unsafe}

safety_pipeline.connect('response_validator', 'output')

from haystack.components.converters import ConversationHistory

class HistoryJailbreakAuditor:
    def __init__(self):
        self.jailbreak_counter = 0

    def audit_history(self, history: ConversationHistory):
        suspicious_turns = 0
        for turn in history.current_turns:
            if self.contains_jailbreak(turn['input']):
                suspicious_turns += 1
        return suspicious_turns > 2

    def contains_jailbreak(self, text: str) -> bool:
        patterns = [r'override.*safety', r'bypass.*guardrails', r'new\s+role']
        return any(re.search(p, text.lower()) for p in patterns)

